5	/// Convert proto SamplingParams to a serde_json map (used as Python dict via PyO3).
6	fn sampling_params_to_map(params: &Option<proto::SamplingParams>) -> serde_json::Value {
7	    match params {
8	        Some(p) => {
9	            let mut map = serde_json::Map::new();
10	            if let Some(v) = p.temperature {
11	                map.insert("temperature".into(), serde_json::json!(v));
12	            }
13	            if let Some(v) = p.top_p {
14	                map.insert("top_p".into(), serde_json::json!(v));
15	            }
16	            if let Some(v) = p.top_k {
17	                map.insert("top_k".into(), serde_json::json!(v));
18	            }
19	            if let Some(v) = p.min_p {
20	                map.insert("min_p".into(), serde_json::json!(v));
21	            }
22	            if let Some(v) = p.frequency_penalty {
23	                map.insert("frequency_penalty".into(), serde_json::json!(v));
24	            }
25	            if let Some(v) = p.presence_penalty {
26	                map.insert("presence_penalty".into(), serde_json::json!(v));
27	            }
28	            if let Some(v) = p.repetition_penalty {
29	                map.insert("repetition_penalty".into(), serde_json::json!(v));
30	            }
31	            if let Some(v) = p.max_new_tokens {
32	                map.insert("max_new_tokens".into(), serde_json::json!(v));
33	            }
34	            if let Some(v) = p.min_new_tokens {
35	                map.insert("min_new_tokens".into(), serde_json::json!(v));
36	            }
37	            if !p.stop.is_empty() {
38	                map.insert("stop".into(), serde_json::json!(p.stop));
39	            }
40	            if !p.stop_token_ids.is_empty() {
41	                map.insert("stop_token_ids".into(), serde_json::json!(p.stop_token_ids));
42	            }
43	            if let Some(v) = p.ignore_eos {
44	                map.insert("ignore_eos".into(), serde_json::json!(v));
45	            }
46	            if let Some(v) = p.n {
47	                map.insert("n".into(), serde_json::json!(v));
48	            }
49	            if let Some(ref v) = p.json_schema {
50	                map.insert("json_schema".into(), serde_json::json!(v));
51	            }
52	            if let Some(ref v) = p.regex {
53	                map.insert("regex".into(), serde_json::json!(v));
54	            }
55	            serde_json::Value::Object(map)
56	        }
57	        None => serde_json::Value::Object(serde_json::Map::new()),
58	    }
59	}
