37	// Disaggregated prefill/decode rendezvous parameters.
38	//
39	// Carried on Generate/TextGenerate requests when the worker is part of a
40	// disaggregated deployment. The prefill leg writes its KV cache to the
41	// bootstrap server identified by (bootstrap_host, bootstrap_port) under
42	// the room id; the decode leg fetches it from the same room. Both legs
43	// receive the same `bootstrap_room` from the router so they rendezvous
44	// on the KV transfer.
45	message DisaggregatedParams {
46	  string bootstrap_host = 1;
47	  int32 bootstrap_port = 2;
